// components/dashboard/AdvancedCharts.tsx
'use client';

import { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, LineChart, Line, PieChart, Pie, Cell, AreaChart, Area } from 'recharts';
import { TrendingUp, TrendingDown, BarChart3, PieChart as PieChartIcon, LineChart as LineChartIcon } from 'lucide-react';

const monthlyData = [
  { month: 'Jan', eia: 45, ec: 32, hybrid: 12, revenue: 450 },
  { month: 'Feb', eia: 52, ec: 38, hybrid: 14, revenue: 520 },
  { month: 'Mar', eia: 48, ec: 42, hybrid: 16, revenue: 480 },
  { month: 'Apr', eia: 60, ec: 45, hybrid: 18, revenue: 600 },
  { month: 'May', eia: 55, ec: 48, hybrid: 20, revenue: 550 },
  { month: 'Jun', eia: 65, ec: 52, hybrid: 22, revenue: 650 },
  { month: 'Jul', eia: 70, ec: 58, hybrid: 25, revenue: 700 },
  { month: 'Aug', eia: 68, ec: 55, hybrid: 23, revenue: 680 },
];

const projectTypeData = [
  { name: 'EIA Projects', value: 45, color: '#10b981' },
  { name: 'EC Projects', value: 32, color: '#3b82f6' },
  { name: 'Hybrid', value: 15, color: '#8b5cf6' },
  { name: 'Others', value: 8, color: '#f59e0b' },
];

const taskStatusData = [
  { name: 'Completed', value: 124, color: '#10b981' },
  { name: 'In Progress', value: 68, color: '#3b82f6' },
  { name: 'Pending', value: 32, color: '#f59e0b' },
  { name: 'Delayed', value: 16, color: '#ef4444' },
];

const revenueData = [
  { month: 'Jan', revenue: 450, expenses: 320 },
  { month: 'Feb', revenue: 520, expenses: 380 },
  { month: 'Mar', revenue: 480, expenses: 350 },
  { month: 'Apr', revenue: 600, expenses: 420 },
  { month: 'May', revenue: 550, expenses: 400 },
  { month: 'Jun', revenue: 650, expenses: 480 },
];

export default function AdvancedCharts() {
  const [activeChart, setActiveChart] = useState<'bar' | 'line' | 'area'>('bar');
  const [timeRange, setTimeRange] = useState('6months');

  return (
    <div className="space-y-6">
      {/* Projects Trend Chart */}
      <div className="bg-white rounded-xl border shadow-sm p-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
          <div>
            <h2 className="text-lg font-semibold text-gray-900">Projects Trend</h2>
            <p className="text-sm text-gray-600">Monthly project distribution by type</p>
          </div>
          <div className="flex gap-3">
            <div className="flex bg-gray-100 rounded-lg p-1">
              <button
                className={`px-3 py-1.5 text-sm rounded-md transition-all ${activeChart === 'bar' ? 'bg-white shadow' : 'hover:bg-gray-200'}`}
                onClick={() => setActiveChart('bar')}
              >
                <BarChart3 className="w-4 h-4 inline mr-2" />
                Bar
              </button>
              <button
                className={`px-3 py-1.5 text-sm rounded-md transition-all ${activeChart === 'line' ? 'bg-white shadow' : 'hover:bg-gray-200'}`}
                onClick={() => setActiveChart('line')}
              >
                <LineChartIcon className="w-4 h-4 inline mr-2" />
                Line
              </button>
              <button
                className={`px-3 py-1.5 text-sm rounded-md transition-all ${activeChart === 'area' ? 'bg-white shadow' : 'hover:bg-gray-200'}`}
                onClick={() => setActiveChart('area')}
              >
                <PieChartIcon className="w-4 h-4 inline mr-2" />
                Area
              </button>
            </div>
            <select 
              className="border rounded-lg px-3 py-1.5 text-sm"
              value={timeRange}
              onChange={(e) => setTimeRange(e.target.value)}
            >
              <option value="3months">Last 3 Months</option>
              <option value="6months">Last 6 Months</option>
              <option value="year">Last Year</option>
            </select>
          </div>
        </div>

        <div className="h-80">
          <ResponsiveContainer width="100%" height="100%">
            {activeChart === 'bar' ? (
              <BarChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip 
                  contentStyle={{ 
                    backgroundColor: 'white',
                    border: '1px solid #e5e7eb',
                    borderRadius: '8px',
                    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
                  }}
                  formatter={(value) => [`${value} projects`, 'Count']}
                />
                <Legend />
                <Bar dataKey="eia" fill="#10b981" name="EIA Projects" radius={[4, 4, 0, 0]} />
                <Bar dataKey="ec" fill="#3b82f6" name="EC Projects" radius={[4, 4, 0, 0]} />
                <Bar dataKey="hybrid" fill="#8b5cf6" name="Hybrid Projects" radius={[4, 4, 0, 0]} />
              </BarChart>
            ) : activeChart === 'line' ? (
              <LineChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Line type="monotone" dataKey="eia" stroke="#10b981" strokeWidth={2} dot={{ r: 4 }} />
                <Line type="monotone" dataKey="ec" stroke="#3b82f6" strokeWidth={2} dot={{ r: 4 }} />
                <Line type="monotone" dataKey="hybrid" stroke="#8b5cf6" strokeWidth={2} dot={{ r: 4 }} />
              </LineChart>
            ) : (
              <AreaChart data={monthlyData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Area type="monotone" dataKey="eia" stackId="1" stroke="#10b981" fill="#10b981" fillOpacity={0.6} />
                <Area type="monotone" dataKey="ec" stackId="1" stroke="#3b82f6" fill="#3b82f6" fillOpacity={0.6} />
                <Area type="monotone" dataKey="hybrid" stackId="1" stroke="#8b5cf6" fill="#8b5cf6" fillOpacity={0.6} />
              </AreaChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>

      {/* Pie Charts Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Project Type Distribution */}
        <div className="bg-white rounded-xl border shadow-sm p-6">
          <h3 className="text-lg font-semibold mb-6">Project Type Distribution</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={projectTypeData}
                  cx="50%"
                  cy="50%"
                  labelLine={false}
                  label={({ name, percent }) => `${name}: ${(percent * 100).toFixed(0)}%`}
                  outerRadius={80}
                  fill="#8884d8"
                  dataKey="value"
                >
                  {projectTypeData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value) => [`${value} projects`, 'Count']}
                />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 grid grid-cols-2 gap-3">
            {projectTypeData.map((item, index) => (
              <div key={index} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                <span className="text-sm">{item.name}</span>
                <span className="text-sm font-semibold ml-auto">{item.value}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Task Status Distribution */}
        <div className="bg-white rounded-xl border shadow-sm p-6">
          <h3 className="text-lg font-semibold mb-6">Task Status Distribution</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={taskStatusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={40}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {taskStatusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip formatter={(value) => [`${value} tasks`, 'Count']} />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 grid grid-cols-2 gap-3">
            {taskStatusData.map((item, index) => (
              <div key={index} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                <span className="text-sm">{item.name}</span>
                <span className="text-sm font-semibold ml-auto">{item.value}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Revenue vs Expenses */}
      <div className="bg-white rounded-xl border shadow-sm p-6">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="text-lg font-semibold">Revenue vs Expenses (₹ Crores)</h3>
            <p className="text-sm text-gray-600">Monthly financial overview</p>
          </div>
          <div className="flex items-center gap-2 text-green-600">
            <TrendingUp className="w-5 h-5" />
            <span className="font-semibold">+18.5% growth</span>
          </div>
        </div>
        <div className="h-80">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={revenueData}>
              <defs>
                <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#10b981" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                </linearGradient>
                <linearGradient id="colorExpenses" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
              <XAxis dataKey="month" />
              <YAxis />
              <Tooltip 
                formatter={(value) => [`₹${value} Cr`, 'Amount']}
                contentStyle={{
                  backgroundColor: 'white',
                  border: '1px solid #e5e7eb',
                  borderRadius: '8px',
                }}
              />
              <Legend />
              <Area type="monotone" dataKey="revenue" stroke="#10b981" fillOpacity={1} fill="url(#colorRevenue)" />
              <Area type="monotone" dataKey="expenses" stroke="#3b82f6" fillOpacity={1} fill="url(#colorExpenses)" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
}